types.syntax:
typedef struct IMG_Animation
{
 int w; /**< The width of the frames */
 int h; /**< The height of the frames */
 int count; /**< The number of frames */
 SDL_Surface **frames; /**< An array of frames */
 int *delays; /**< An array of frame delays, in milliseconds */
} IMG_Animation;

enums.syntax:
typedef enum IMG_AnimationDecoderStatus
{
 IMG_DECODER_STATUS_INVALID = -1, /**< تعاد هذه القيمة عندما يكون مفكك الرسوم المتحركة غير صالح، فتوقف SDL3_image محاولة متابعة فك الإطارات. */
 IMG_DECODER_STATUS_OK, /**< تعاد هذه القيمة عندما يصبح مفكك الرسوم المتحركة جاهزًا، فتستطيع SDL3_image متابعة فك الإطار التالي. */
 IMG_DECODER_STATUS_FAILED, /**< تعاد هذه القيمة عندما يفشل فك إطار جديد، فتتوقف SDL3_image عن هذا المسار حتى يعالج التطبيق الخطأ. */
 IMG_DECODER_STATUS_COMPLETE  /**< تعاد هذه القيمة عندما تنتهي الإطارات المتاحة، فتفهم SDL3_image أن تسلسل الرسوم المتحركة اكتمل. */
} IMG_AnimationDecoderStatus;
